def validate(args, output):
    nums = args[0]
    if not isinstance(output, list) or len(output) != len(nums):
        return False
    from collections import Counter
    if Counter(output) != Counter(nums):
        return False
    seen_odd = False
    for v in output:
        if v % 2 == 0:
            if seen_odd:
                return False
        else:
            seen_odd = True
    return True

