function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output) || output.length !== nums.length) return false;
    const c = new Map();
    for (const v of nums) c.set(v, (c.get(v) || 0) + 1);
    for (const v of output) {
        if (!c.has(v)) return false;
        c.set(v, c.get(v) - 1);
        if (c.get(v) === 0) c.delete(v);
    }
    if (c.size !== 0) return false;
    let seenOdd = false;
    for (const v of output) {
        if (((v % 2) + 2) % 2 === 0) {
            if (seenOdd) return false;
        } else {
            seenOdd = true;
        }
    }
    return true;
}

