solutions.javascript:
var sortArrayByParity = function(nums) {
    const evens = nums.filter(x => x % 2 === 0).sort((a, b) => a - b);
    const odds = nums.filter(x => x % 2 === 1).sort((a, b) => a - b);
    return evens.concat(odds);
};
